"""matplotlib.patches compatibility — provides Patch classes that integrate with our plotly shim."""

class Patch:
    """Base patch class."""
    def __init__(self, **kwargs):
        self.kwargs = kwargs
        self._facecolor = kwargs.get('facecolor', kwargs.get('fc', kwargs.get('color', None)))
        self._edgecolor = kwargs.get('edgecolor', kwargs.get('ec', None))
        self._linewidth = kwargs.get('linewidth', kwargs.get('lw', 1))
        self._alpha = kwargs.get('alpha', None)
        self._fill = kwargs.get('fill', True)
        self._label = kwargs.get('label', None)
    def set_facecolor(self, c): self._facecolor = c
    def set_edgecolor(self, c): self._edgecolor = c
    def set_alpha(self, a): self._alpha = a
    def set_linewidth(self, w): self._linewidth = w
    def get_facecolor(self): return self._facecolor
    def get_edgecolor(self): return self._edgecolor

class Rectangle(Patch):
    """Rectangle patch — Rectangle(xy, width, height, angle=0, ...)"""
    def __init__(self, xy=(0,0), width=1, height=1, angle=0, **kwargs):
        super().__init__(**kwargs)
        self.xy = xy
        self.width = width
        self.height = height
        self.angle = angle
    def get_xy(self): return self.xy
    def get_width(self): return self.width
    def get_height(self): return self.height
    def set_xy(self, xy): self.xy = xy
    def set_width(self, w): self.width = w
    def set_height(self, h): self.height = h

class FancyBboxPatch(Rectangle):
    """Fancy bounding box patch."""
    def __init__(self, xy=(0,0), width=1, height=1, boxstyle="round", **kwargs):
        super().__init__(xy, width, height, **kwargs)
        self.boxstyle = boxstyle

class Circle(Patch):
    """Circle patch — Circle(center, radius, ...)"""
    def __init__(self, xy=(0,0), radius=1, **kwargs):
        # matplotlib uses 'xy' not 'center'
        super().__init__(**kwargs)
        self.center = xy
        self.radius = radius

class Ellipse(Patch):
    def __init__(self, xy=(0,0), width=1, height=1, angle=0, **kwargs):
        super().__init__(**kwargs)
        self.center = xy
        self.width = width
        self.height = height
        self.angle = angle

class Arc(Ellipse):
    def __init__(self, xy=(0,0), width=1, height=1, angle=0, theta1=0, theta2=360, **kwargs):
        super().__init__(xy, width, height, angle, **kwargs)
        self.theta1 = theta1
        self.theta2 = theta2

class Wedge(Patch):
    def __init__(self, center=(0,0), r=1, theta1=0, theta2=360, **kwargs):
        super().__init__(**kwargs)
        self.center = center
        self.r = r
        self.theta1 = theta1
        self.theta2 = theta2

class Polygon(Patch):
    def __init__(self, xy=None, closed=True, **kwargs):
        super().__init__(**kwargs)
        self.xy = xy if xy is not None else []
        self.closed = closed

class RegularPolygon(Patch):
    def __init__(self, xy=(0,0), numVertices=5, radius=1, orientation=0, **kwargs):
        super().__init__(**kwargs)
        self.xy = xy
        self.numVertices = numVertices
        self.radius = radius

class FancyArrowPatch(Patch):
    def __init__(self, posA=None, posB=None, path=None, arrowstyle='->', **kwargs):
        super().__init__(**kwargs)
        self.posA = posA
        self.posB = posB
        self.arrowstyle = arrowstyle

class Arrow(Patch):
    def __init__(self, x=0, y=0, dx=1, dy=0, width=0.2, **kwargs):
        super().__init__(**kwargs)
        self.x = x
        self.y = y
        self.dx = dx
        self.dy = dy

class PathPatch(Patch):
    def __init__(self, path=None, **kwargs):
        super().__init__(**kwargs)
        self.path = path

class ConnectionPatch(FancyArrowPatch):
    def __init__(self, xyA=(0,0), xyB=(1,1), coordsA='data', coordsB='data', **kwargs):
        super().__init__(posA=xyA, posB=xyB, **kwargs)
        self.coordsA = coordsA
        self.coordsB = coordsB
